define('plantshare/manage_sightings',[
    'bridge/jquery',
    'lib/picnet.table.filter.min',
    'util/shadowbox_init'
], function ($, table_filter, Shadowbox) {
    $(document).ready(function () {
        // Set up table filtering.
        var options = {
            enableCookies: true,
            filterDelay: 400,
            filteredRows: function () {
                // Update the message indicating how many sightings are shown.
                var ROWS_SELECTOR = '.list tbody tr';
                var num_rows = $(ROWS_SELECTOR).length;
                var num_hidden_rows = $(
                    ROWS_SELECTOR + '[style="display: none;"]').length;
                var num_showing = num_rows - num_hidden_rows;
                var message = '.';
                if (num_showing < num_rows) {
                    message = ', filtered to ' + num_showing + '.';
                }
                $('.showing').html(message);
            }
        };
        $('.content table').tableFilter(options);
    });
});

/* Redirect the old question URL format to the current one:
 * /questions/all/#q{id} --> /questions/all/{year}/#q{id}
 * This is
 * done on the client side because fragment identifiers (# hashes)
 * do not get sent to the server side.
 */

define('plantshare/redirect_old_question_urls',[
    'bridge/jquery'
], function ($) {

    $(document).ready(function () {

        // Only consider redirecting if the URL has no year on the end
        // and a hash is present.
        var no_year = window.location.href.toString().split('#')[0].endsWith(
            '/all/');
        if (no_year && window.location.hash) {
            // Check if there's a matching id in this page. If not,
            // redirect to let the server figure out the final URL.
            var hash = window.location.hash.split('?')[0];
            var found = $(hash);
            if (found.length === 0) {
                var parts = hash.split('q');
                var question_id = parts[1];
                if (question_id.length > 0) {
                    var url = '/plantshare/questions/all/?q=' + question_id +
                        '#q' + question_id;
                    // Redirect to the server side for a final redirect.
                    // The hash will carry through to the final URL.
                    window.location.replace(url);
                }
            }
        }

    });

});

