/* Activate any video links to make them open in a lightbox. */

require([
    'bridge/jquery',
    'bridge/shadowbox',
    'util/shadowbox_init'
], function($, Shadowbox, shadowbox_init) {
    $(document).ready(function() {
        $('a.video').each(function() {
            // On iOS, instead of trying to use the lightbox for videos
            // (due to buggy behavior that requires scrolling to the top),
            // use a link that will open in the device's YouTube app.
            if (navigator.userAgent.match(/(iPad|iPod|iPhone)/)) {
                var start = this.href.lastIndexOf('/') + 1;
                var end = this.href.indexOf('?');
                var video_id = this.href.substring(start, end);
                var youtube_app_url = '//www.youtube.com/v/' + video_id;
                this.href = youtube_app_url;
            }
            else {
                // Open the video in a lightbox.
                var link = this;
                $(this).click(function() {
                    Shadowbox.open({
                        content: link.href,
                        player: "iframe"
                    });
                    return false;
                });
            }
        });
    });
});

define("util/activate_video_links", function(){});

require([
    'util/activate_image_gallery',
    'bridge/shadowbox',
    'util/shadowbox_init',
    'util/activate_video_links',
    'util/glossarizer'
], function(activate_image_gallery, Shadowbox, shadowbox_init,
            activate_video_links, glossarizer) {
    $(document).ready(function () {
        glossarizer.glossarize($('.key-char + p, .exceptions + p'));

        // Allow activating the image gallery dialog using the keyboard.
        $('.img-gallery .frame').on('keydown', function (event) {
            var keyCode = event.which;
            if (keyCode == 32) {   // Space key
                // Prevent page scrolling on pressing Space.
                event.preventDefault();
            }
        });
        $('.img-gallery .frame').on('keyup', function (event) {
            var keyCode = event.which;
            if (keyCode == 13 || keyCode == 32) {   // Return, Space keys
                $(event.target).trigger('click');
            }
        });
    });
});

